/**
 * FINIFY AI: TERMINAL CORE PALETTE
 * Optimized for high-density financial data and agentic debate UI.
 */

export const darkTheme = {
  // --- Surface & Depth ---
  '--bg-color': '#0a0a0a',            // Pure Charcoal (Base)
  '--card-bg': '#141414',             // Elevated Surface
  '--input-bg': 'rgba(0, 0, 0, 0.4)',  // Recessed Command Line
  '--nav-bg': 'rgba(10, 10, 10, 0.8)', // Frosted Glass Header
  
  // --- Branding & Accents ---
  '--primary-accent': '#10b981',      // Emerald 500
  '--primary-hover': '#34d399',       // Emerald 400
  '--accent-glow': 'rgba(16, 185, 129, 0.15)',
  
  // --- Typography ---
  '--text-main': '#f9fafb',           // Neutral 50
  '--text-muted': '#6b7280',          // Neutral 500
  '--text-dim': '#374151',            // Neutral 700
  
  // --- Infrastructure ---
  '--border-color': 'rgba(255, 255, 255, 0.08)',
  '--border-active': 'rgba(16, 185, 129, 0.4)',
  '--card-shadow': '0 20px 40px rgba(0, 0, 0, 0.6)',
};

export const lightTheme = {
  // --- Surface & Depth (Silver Terminal Variant) ---
  '--bg-color': '#f3f4f6',           
  '--card-bg': '#ffffff',
  '--input-bg': '#f9fafb',
  '--nav-bg': 'rgba(243, 244, 246, 0.8)',
  
  // --- Branding & Accents ---
  '--primary-accent': '#059669',      // Emerald 600 (Higher contrast for light mode)
  '--primary-hover': '#047857',
  '--accent-glow': 'rgba(5, 150, 105, 0.1)',
  
  // --- Typography ---
  '--text-main': '#111827',
  '--text-muted': '#4b5563',
  '--text-dim': '#9ca3af',
  
  // --- Infrastructure ---
  '--border-color': '#e5e7eb',
  '--border-active': 'rgba(5, 150, 105, 0.3)',
  '--card-shadow': '0 10px 25px rgba(0, 0, 0, 0.03)',
};
